from fastapi import APIRouter
from fastapi.responses import HTMLResponse

router = APIRouter(tags=["external-lab-snapshot-reader-frontend"])

HTML = """
<!doctype html><html lang="pt-PT"><head><meta charset="utf-8"/><meta name="viewport" content="width=device-width, initial-scale=1"/><title>Lab Snapshot Reader</title><style>:root{color-scheme:dark;--panel:#0f172a;--line:#26344f;--text:#eef5ff;--muted:#9fb0d0}*{box-sizing:border-box}body{margin:0;font-family:Inter,Arial,sans-serif;background:radial-gradient(circle at top,#14345b,#050816 55%);color:var(--text)}.page{padding:10px;display:grid;gap:10px}.panel{background:rgba(15,23,42,.94);border:1px solid var(--line);border-radius:22px;padding:13px}h1,h2{margin:.1rem 0}.muted{color:var(--muted)}.grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(190px,1fr));gap:8px}.buttons{display:grid;grid-template-columns:repeat(auto-fit,minmax(150px,1fr));gap:8px}button,input,textarea,select{font:inherit;border-radius:16px;border:1px solid var(--line);background:#0b1220;color:var(--text);padding:12px}button{background:linear-gradient(135deg,#0284c7,#38bdf8);border:none;color:#02101b;font-weight:1000}button.dark{background:#0b1220;color:var(--text);border:1px solid var(--line)}textarea{width:100%;min-height:180px}pre{white-space:pre-wrap;overflow:auto;font-size:12px;max-height:520px;background:#081226;border:1px solid var(--line);border-radius:18px;padding:12px}@media(max-width:760px){.buttons{grid-template-columns:1fr}}</style></head><body><div class="page"><section class="panel"><h1>External Lab Snapshot Reader</h1><p class="muted">Phase 200: ler snapshots das labs, criar candidatos nativos e preparar evolução controlada sem aplicar código às cegas.</p><div class="buttons"><button onclick="location.href='/app/home'" class="dark">Home</button><button onclick="location.href='/app/external-skills-lab-registry'" class="dark">Skills Labs</button><button onclick="dashboard()">Dashboard</button><button onclick="seedCandidates()">Gerar candidatos pelo registry</button></div></section><section class="panel"><h2>Colar docs/UPSTREAM_SNAPSHOT.json</h2><div class="grid"><input id="labId" value="openai_skills_lab"/><input id="labRepo" value="AndreVazao/godmode-openai-skills-lab"/></div><input id="goal" style="width:100%;margin-top:8px" value="Melhorar God Mode, Android cockpit, provider router, deploy cloud e VerbaForge com skills nativas controladas."/><textarea id="snapshot">{"upstream":"openai/skills","imported_at":"manual","file_count":0,"skill_count":3,"skills":["upstream/skills/agents/SKILL.md","upstream/skills/github-actions/SKILL.md","upstream/skills/android/SKILL.md"],"policy":"lab only; no secrets"}</textarea><button onclick="ingest()">Ler snapshot + criar candidatos</button></section><section class="panel"><h2>Candidatos</h2><div class="grid"><select id="domain"><option value="">todos domínios</option><option>god_mode_core</option><option>android_mobile</option><option>provider_router</option><option>cloud_deploy</option><option>verbaforge_content</option><option>github_workflow</option><option>browser_quarantine</option></select><select id="risk"><option value="">todos riscos</option><option>low_risk</option><option>medium_risk</option><option>high_risk</option></select></div><button onclick="candidates()">Listar candidatos</button><p class="muted">Para criar plano de um candidato, copia o candidate_id para baixo.</p><input id="candidateId" style="width:100%" placeholder="candidate_id"/><button onclick="candidatePlan()">Criar plano gated do candidato</button></section><section class="panel"><h2>Resultado</h2><pre id="out"></pre></section></div><script>const qs=s=>document.querySelector(s);async function api(p,o){const r=await fetch(p,o);const t=await r.text();let j;try{j=JSON.parse(t)}catch{j={raw:t}};if(!r.ok)throw new Error(t);return j}function show(x){qs('#out').textContent=JSON.stringify(x,null,2)}async function dashboard(){show(await api('/api/external-lab-snapshot-reader/dashboard'))}async function seedCandidates(){show(await api('/api/external-lab-snapshot-reader/generate-candidates-from-registry',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({operator_goal:qs('#goal').value})}))}async function ingest(){show(await api('/api/external-lab-snapshot-reader/ingest-snapshot-text',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({lab_id:qs('#labId').value,lab_repo_full_name:qs('#labRepo').value,snapshot_text:qs('#snapshot').value,operator_goal:qs('#goal').value})}))}async function candidates(){const d=qs('#domain').value,r=qs('#risk').value;show(await api('/api/external-lab-snapshot-reader/candidates?limit=150'+(d?'&domain='+encodeURIComponent(d):'')+(r?'&risk='+encodeURIComponent(r):'')))}async function candidatePlan(){show(await api('/api/external-lab-snapshot-reader/create-candidate-plan',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({candidate_id:qs('#candidateId').value,target_project:'GOD_MODE'})}))}dashboard()</script></body></html>
"""


@router.get('/app/external-lab-snapshot-reader', response_class=HTMLResponse)
async def external_lab_snapshot_reader_frontend() -> HTMLResponse:
    return HTMLResponse(content=HTML)


@router.get('/app/lab-snapshot-reader', response_class=HTMLResponse)
async def lab_snapshot_reader_alias() -> HTMLResponse:
    return HTMLResponse(content=HTML)
